// packages/database/src/db/schema/email-address.ts
// Drizzle table: emailAddress (generated by scripts/split-schema.ts)

import { createId } from '@paralleldrive/cuid2'
import { pgTable, text, uniqueIndex } from './_shared'

/** Drizzle table for emailAddress */
export const EmailAddress = pgTable(
  'EmailAddress',
  {
    id: text()
      .$defaultFn(() => createId())
      .primaryKey()
      .notNull(),
    name: text(),
    address: text().notNull(),
    raw: text(),
    integrationId: text().notNull(),
    integrationType: text().notNull(),
  },
  (table) => [
    uniqueIndex('EmailAddress_integrationId_address_key').using(
      'btree',
      table.integrationId.asc().nullsLast(),
      table.address.asc().nullsLast()
    ),
  ]
)
